+fn cache_insert<K, V>(
+    map: &mut AHashMap<K, V>,
+    fifo: &mut VecDeque<K>,
+    capacity: usize,
+    key: K,
+    value: V,
+) where
+    K: Copy + Eq + Hash,
+{
